const kdNr = $json.body?.kdNr ?? $json.kdNr ?? $json.query?.kdNr;

if (!kdNr || String(kdNr).trim() === "") {
  return [
    {
      json: {
        inputValid: false,
        success: false,
        request: {
          kdNr: null
        },
        customer: {
          kdNr: null,
          displayName: null,
          company: null
        },
        summary: {
          orderCount: 0,
          positionCount: 0
        },
        orders: [],
        speech: {
          summaryText: "Es wurde keine Kundennummer übergeben."
        },
        error: {
          code: "MISSING_KDNR",
          message: "kdNr fehlt im Request."
        }
      }
    }
  ];
}

const kdNrClean = String(kdNr).trim();

return [
  {
    json: {
      inputValid: true,
      kdNr: kdNrClean,
      method: "GET",
      path: `/customers/${kdNrClean}/orders`,
      bodyString: ""
    }
  }
];

const input = $input.first().json;

function cleanValue(value) {
  if (value === undefined || value === null) return null;
  const text = String(value).trim();
  return text === "" ? null : text;
}

function toNumberOrNull(value) {
  if (value === undefined || value === null || value === "") return null;
  const num = Number(value);
  return Number.isNaN(num) ? null : num;
}

function buildResponse({
  success,
  requestKdNr,
  customerKdNr = null,
  displayName = null,
  company = null,
  orders = [],
  error = null,
  summaryText = null
}) {
  const orderCount = orders.length;
  const positionCount = orders.reduce((sum, order) => sum + order.positions.length, 0);

  return {
    success,
    request: {
      kdNr: requestKdNr
    },
    customer: {
      kdNr: customerKdNr ?? requestKdNr ?? null,
      displayName: displayName ?? null,
      company: company ?? null
    },
    summary: {
      orderCount,
      positionCount
    },
    orders,
    speech: {
      summaryText:
        summaryText ??
        (success
          ? `Ich habe ${orderCount} Aufträge mit insgesamt ${positionCount} Positionen gefunden.`
          : "Die Anfrage konnte nicht erfolgreich verarbeitet werden.")
    },
    error
  };
}

const success = input.ok === true;
const requestKdNr = cleanValue(input.kdNr);
const rows = Array.isArray(input.rows) ? input.rows : [];

// Fall 1: API-Antwort nicht erfolgreich
if (!success) {
  return [
    {
      json: buildResponse({
        success: false,
        requestKdNr,
        error: {
          code: "UPSTREAM_REQUEST_FAILED",
          message: "Die API hat keinen erfolgreichen Status zurückgegeben."
        },
        summaryText: "Die Anfrage konnte nicht erfolgreich verarbeitet werden."
      })
    }
  ];
}

// Fall 2: Erfolgreich, aber keine Treffer
if (rows.length === 0) {
  return [
    {
      json: buildResponse({
        success: true,
        requestKdNr,
        summaryText: requestKdNr
          ? `Ich habe leider keine Aufträge für die Kundennummer ${requestKdNr} gefunden.`
          : "Ich habe leider keine Aufträge gefunden."
      })
    }
  ];
}

// Kundendaten aus erster Zeile
const firstRow = rows[0];

const customerKdNr =
  cleanValue(firstRow.KdNr) ??
  cleanValue(firstRow.kdNr) ??
  requestKdNr;

const displayName =
  cleanValue(firstRow.displayName) ??
  cleanValue(firstRow.DisplayName);

const company =
  cleanValue(firstRow.Firma) ??
  cleanValue(firstRow.firma) ??
  cleanValue(firstRow.Company);

// Nach AuftragsID gruppieren
const ordersMap = new Map();

for (const row of rows) {
  const orderId =
    toNumberOrNull(row.AuftragsID) ??
    toNumberOrNull(row.auftragsID) ??
    toNumberOrNull(row.orderId);

  // Zeilen ohne gültige AuftragsID überspringen
  if (orderId === null) {
    continue;
  }

  if (!ordersMap.has(orderId)) {
    const invoiceNumber =
      cleanValue(row.Rechnungsnummer) ??
      cleanValue(row.rechnungsnummer) ??
      cleanValue(row.invoiceNumber);

    const comment =
      cleanValue(row.voice_agent_comment) ??
      cleanValue(row.comment);

    ordersMap.set(orderId, {
      orderId,
      invoiceNumber,
      comment,
      positions: []
    });
  }

  const position =
    toNumberOrNull(row.AuftragsPos) ??
    toNumberOrNull(row.auftragsPos) ??
    toNumberOrNull(row.position);

  const model =
    cleanValue(row.Modellbezeichnung) ??
    cleanValue(row.modellbezeichnung) ??
    cleanValue(row.model);

  const cartridge =
    cleanValue(row.Cartridge) ??
    cleanValue(row.cartridge);

  const quantity =
    toNumberOrNull(row.Einheit) ??
    toNumberOrNull(row.einheit) ??
    toNumberOrNull(row.quantity);

  ordersMap.get(orderId).positions.push({
    position,
    model,
    cartridge,
    quantity
  });
}

let orders = Array.from(ordersMap.values());

// Falls alle Zeilen wegen fehlender AuftragsID herausgefiltert wurden
if (orders.length === 0) {
  return [
    {
      json: buildResponse({
        success: false,
        requestKdNr,
        customerKdNr,
        displayName,
        company,
        error: {
          code: "INVALID_ORDER_DATA",
          message: "Die API hat keine verwertbaren Auftragsdaten geliefert."
        },
        summaryText: "Es wurden keine verwertbaren Auftragsdaten geliefert."
      })
    }
  ];
}

// Positionen ohne Inhalt optional herausfiltern
orders = orders.map(order => {
  const filteredPositions = order.positions.filter(pos => {
    return (
      pos.position !== null ||
      pos.model !== null ||
      pos.cartridge !== null ||
      pos.quantity !== null
    );
  });

  return {
    ...order,
    positions: filteredPositions
  };
});

// Sortieren
orders.sort((a, b) => a.orderId - b.orderId);

for (const order of orders) {
  order.positions.sort((a, b) => {
    const aPos = a.position ?? 0;
    const bPos = b.position ?? 0;
    return aPos - bPos;
  });
}

const orderCount = orders.length;
const positionCount = orders.reduce((sum, order) => sum + order.positions.length, 0);

// Natürlichere Sprachzusammenfassung
let summaryText;

if (orderCount === 0) {
  summaryText = requestKdNr
    ? `Ich habe leider keine Aufträge für die Kundennummer ${requestKdNr} gefunden.`
    : "Ich habe leider keine Aufträge gefunden.";
} else {
  let subject = null;

  if (company) {
    subject = `die Firma ${company}`;
  } else if (displayName) {
    subject = `den Käufer ${displayName}`;
  } else if (customerKdNr) {
    subject = `die Kundennummer ${customerKdNr}`;
  }

  const auftragText = orderCount === 1 ? "1 Auftrag" : `${orderCount} Aufträge`;
  const positionsText = positionCount === 1 ? "1 Position" : `${positionCount} Positionen`;

  summaryText = subject
    ? `Ich habe ${auftragText} mit insgesamt ${positionsText} für ${subject} gefunden.`
    : `Ich habe ${auftragText} mit insgesamt ${positionsText} gefunden.`;
}

return [
  {
    json: buildResponse({
      success: true,
      requestKdNr,
      customerKdNr,
      displayName,
      company,
      orders,
      summaryText
    })
  }
];

const data = { ...$json };
delete data.inputValid;

return [{ json: data }];
